// АВТО-ИЗВЛЕЧЕНО из public/practice/fairytales.html (два <style>-блока из <head>).
// Источник правды — движок «Fairytale's World»; при обновлении HTML перегенерировать
// скриптом extract-fairytale.js (см. описание в src/practice/fairytale/README.md).
export const CSS_BASE = ":root{\n  --frost:#eef1ff; --frost-dim:#b9b0e0; --amber:#ffd27a; --amber-deep:#e8a63c;\n  --deep:#0a0f22; --midnight:#060a17; --rose:#ffb4c8;\n  --parch:#efe2c4; --parch-ink:#3a2c18;\n  /* JustToStudy brand */\n  --brand:#8b5cf6; --brand2:#e5399b; --brand-lo:#6d3be0; --brand-deep:#160a2e; --brand-deep2:#0c0620;\n  --ui:'Onest','Montserrat',-apple-system,'SF Pro Display','Segoe UI',Roboto,system-ui,sans-serif;\n  --body:'Onest','Montserrat',-apple-system,'SF Pro Text','Segoe UI',Roboto,system-ui,sans-serif;\n}\n*{box-sizing:border-box;-webkit-tap-highlight-color:transparent;}\nhtml,body{margin:0;height:100%;background:var(--midnight);overflow:hidden;-webkit-text-size-adjust:100%;\n  font-family:var(--body);color:var(--frost);user-select:none;-webkit-font-smoothing:antialiased;text-rendering:optimizeLegibility;}\n/* JustToStudy wordmark */\n.jts{position:absolute;top:calc(14px + env(safe-area-inset-top));left:16px;z-index:8;display:flex;align-items:center;gap:.5em;pointer-events:none;}\n.jts .dot{width:26px;height:26px;border-radius:9px;background:linear-gradient(135deg,var(--brand),var(--brand2));\n  box-shadow:0 4px 16px rgba(139,92,246,.5);display:flex;align-items:center;justify-content:center;font-family:var(--ui);font-weight:800;color:#fff;font-size:15px;}\n.jts .wm{font-family:var(--ui);font-weight:700;font-size:13px;letter-spacing:.02em;color:var(--frost);text-shadow:0 2px 8px rgba(0,0,0,.5);}\n.jts .wm b{background:linear-gradient(135deg,var(--brand),var(--brand2));-webkit-background-clip:text;background-clip:text;color:transparent;}\n#app{position:fixed;inset:0;overflow:hidden;}\n.screen{position:absolute;inset:0;opacity:0;pointer-events:none;transition:opacity .9s ease;}\n.screen.on{opacity:1;pointer-events:auto;}\nimg{-webkit-user-drag:none;user-drag:none;}\n\n.btn{position:relative;display:inline-flex;align-items:center;justify-content:center;\n  gap:.5em;padding:.85em 1.7em;margin:.3em;cursor:pointer;min-height:48px;\n  font-family:var(--ui);font-weight:700;letter-spacing:.02em;font-size:15px;\n  color:#fff;border:none;border-radius:16px;\n  background:linear-gradient(135deg,var(--brand),var(--brand2));\n  box-shadow:0 10px 26px rgba(139,92,246,.4),inset 0 1px 0 rgba(255,255,255,.35);\n  transition:transform .15s ease,filter .2s ease,box-shadow .2s;}\n.btn:hover{filter:brightness(1.06);transform:translateY(-1px);box-shadow:0 14px 32px rgba(229,57,155,.45);}\n.btn:active{transform:translateY(1px) scale(.98);}\n.btn.ghost{background:rgba(255,255,255,.06);color:var(--frost);\n  border:1px solid rgba(160,140,230,.4);backdrop-filter:blur(8px);box-shadow:0 4px 16px rgba(0,0,0,.3);}\n.btn.ghost:hover{filter:brightness(1.15);background:rgba(255,255,255,.1);}\n\n#title{background:#060a17 center/cover no-repeat;}\n#title::after{content:\"\";position:absolute;inset:0;\n  background:radial-gradient(120% 90% at 50% 8%,transparent 40%,rgba(6,10,23,.55) 78%,rgba(6,10,23,.95));}\n#titleArt{position:absolute;inset:0;background:center/cover no-repeat;\n  animation:titleDrift 26s ease-in-out infinite alternate;transform-origin:center;}\n@keyframes titleDrift{from{transform:scale(1.04)}to{transform:scale(1.14) translateY(-1.5%)}}\n.title-wrap{position:absolute;inset:0;display:flex;flex-direction:column;\n  align-items:center;justify-content:flex-end;padding-bottom:9vh;text-align:center;z-index:3;}\n.title-kicker{font-family:var(--ui);letter-spacing:.5em;font-size:12px;\n  color:var(--amber);text-transform:uppercase;opacity:.85;text-shadow:0 2px 12px #000;margin-bottom:.4em;}\n.title-name{font-family:var(--ui);font-size:min(13vw,86px);line-height:.95;letter-spacing:.04em;\n  color:var(--frost);margin:0;text-shadow:0 2px 4px #000,0 0 40px rgba(150,200,255,.35);}\n.title-sub{font-style:italic;font-size:min(4.5vw,20px);color:var(--frost-dim);\n  margin:.6em 0 1.4em;text-shadow:0 2px 10px #000;}\n.title-btns{display:flex;flex-wrap:wrap;justify-content:center;}\n.title-lang{position:absolute;top:calc(14px + env(safe-area-inset-top));right:14px;z-index:4;display:flex;gap:6px;}\n.langchip{padding:.35em .7em;border-radius:20px;cursor:pointer;font-family:var(--ui);font-size:11px;letter-spacing:.08em;\n  background:rgba(14,24,52,.7);border:1px solid rgba(150,190,255,.3);color:var(--frost);}\n.langchip.sel{background:linear-gradient(180deg,#ffe9b8,#e8b25a);color:#12203c;border-color:var(--amber);}\n\n/* ---------- LIBRARY ---------- */\n#library{background:radial-gradient(120% 90% at 50% -5%,#2a1655,var(--brand-deep) 45%,var(--brand-deep2) 78%);overflow-y:auto;}\n.lib-lang{position:absolute;top:calc(14px + env(safe-area-inset-top));right:14px;z-index:6;display:flex;gap:6px;}\n.lib-head{text-align:center;padding:8vh 6vw 2vh;}\n.lib-head h2{font-family:var(--ui);font-weight:800;letter-spacing:-.01em;font-size:clamp(24px,7vw,34px);margin:.1em;color:var(--frost);}\n.lib-head p{color:var(--frost-dim);font-style:italic;margin:.2em;font-size:15px;}\n.lib-grid{display:flex;flex-wrap:wrap;gap:22px;justify-content:center;align-items:stretch;padding:2vh 6vw 8vh;max-width:1000px;margin:0 auto;}\n.tale-card{flex:0 0 auto;width:min(88vw,340px);border-radius:20px;overflow:hidden;cursor:pointer;position:relative;\n  background:rgba(16,26,52,.6);border:1px solid rgba(150,190,255,.2);box-shadow:0 18px 44px rgba(0,0,0,.5);\n  transition:transform .3s ease,box-shadow .3s ease,border-color .3s;display:flex;flex-direction:column;}\n.tale-card:hover{transform:translateY(-6px);border-color:var(--amber);box-shadow:0 26px 56px rgba(0,0,0,.6),0 0 34px rgba(255,200,120,.2);}\n.tale-cover{height:180px;position:relative;background:center/cover no-repeat;}\n.tale-cover::after{content:\"\";position:absolute;inset:0;background:linear-gradient(0deg,rgba(10,16,34,.85),transparent 60%);}\n.tale-cover .badge{position:absolute;top:12px;left:12px;z-index:2;font-family:var(--ui);font-size:10px;letter-spacing:.1em;\n  text-transform:uppercase;padding:.3em .7em;border-radius:20px;background:rgba(8,12,26,.7);border:1px solid rgba(150,190,255,.35);color:var(--frost);}\n.tale-cover .badge.done{border-color:var(--amber);color:var(--amber);}\n.tale-body{padding:1em 1.2em 1.3em;display:flex;flex-direction:column;gap:.5em;flex:1;}\n.tale-body h3{font-family:var(--ui);letter-spacing:.06em;font-size:19px;margin:0;color:var(--frost);text-transform:uppercase;line-height:1.15;}\n.tale-body .desc{font-size:14px;color:var(--frost-dim);line-height:1.45;flex:1;}\n.tale-meta{display:flex;flex-wrap:wrap;gap:.4em .9em;font-size:12px;color:var(--frost-dim);}\n.tale-meta b{color:var(--amber);font-weight:normal;font-family:var(--ui);letter-spacing:.04em;}\n.tale-prog{height:6px;border-radius:4px;background:rgba(10,18,40,.8);overflow:hidden;}\n.tale-prog i{display:block;height:100%;background:linear-gradient(90deg,#5aa0ff,#ffd27a);width:0;transition:width .6s;}\n.tale-card .btn{align-self:flex-start;margin:.3em 0 0;}\n\n#select{background:radial-gradient(120% 110% at 50% -10%,#26134e,var(--brand-deep) 55%,var(--brand-deep2) 82%);}\n.hall-head{position:absolute;top:0;left:0;right:0;text-align:center;padding:5vh 4vw 1vh;z-index:2;}\n.hall-head h2{font-family:var(--ui);letter-spacing:.12em;font-size:min(6vw,26px);margin:.1em;color:var(--frost);text-transform:uppercase;}\n.hall-head p{color:var(--frost-dim);font-style:italic;margin:.2em;font-size:15px;}\n.hall{position:absolute;inset:0;display:flex;align-items:center;gap:2.4vw;\n  overflow-x:auto;overflow-y:hidden;padding:20vh 6vw 6vh;\n  scroll-snap-type:x mandatory;-webkit-overflow-scrolling:touch;z-index:1;}\n.hall::-webkit-scrollbar{display:none;}\n.hero-card{flex:0 0 auto;width:min(64vw,300px);height:66vh;position:relative;\n  scroll-snap-align:center;cursor:pointer;border-radius:22px;overflow:hidden;\n  background:linear-gradient(180deg,rgba(40,60,110,.35),rgba(10,18,40,.7));\n  border:1px solid rgba(150,190,255,.22);box-shadow:0 20px 50px rgba(0,0,0,.5);\n  transition:transform .35s ease,box-shadow .35s ease,border-color .35s;}\n.hero-card:hover{transform:translateY(-8px);border-color:var(--amber);\n  box-shadow:0 30px 60px rgba(0,0,0,.6),0 0 40px rgba(255,200,120,.25);}\n.hero-card .glow{position:absolute;inset:0;background:radial-gradient(70% 55% at 50% 65%,rgba(140,190,255,.35),transparent 70%);}\n.hero-card .spr{position:absolute;left:50%;bottom:16%;transform:translateX(-50%);height:70%;\n  filter:drop-shadow(0 18px 22px rgba(0,0,0,.55));animation:heroBob 5s ease-in-out infinite;}\n@keyframes heroBob{0%,100%{transform:translateX(-50%) translateY(0)}50%{transform:translateX(-50%) translateY(-2.5%)}}\n.hero-card .plate{position:absolute;left:0;right:0;bottom:0;padding:1.2em 1.1em 1.4em;text-align:center;\n  background:linear-gradient(0deg,rgba(6,10,23,.92),transparent);}\n.hero-card .plate h3{font-family:var(--ui);letter-spacing:.1em;font-size:19px;margin:.1em;color:var(--frost);text-transform:uppercase;}\n.hero-card .plate .role{color:var(--amber);font-style:italic;font-size:14px;}\n.hall-nav{position:absolute;bottom:3vh;left:0;right:0;text-align:center;z-index:3;color:var(--frost-dim);font-style:italic;font-size:13px;}\n\n#detail{background:radial-gradient(120% 120% at 50% -10%,#26134e,var(--brand-deep2) 72%);display:flex;align-items:center;justify-content:center;}\n.detail-inner{position:relative;width:100%;max-width:820px;height:100%;display:flex;align-items:center;justify-content:center;}\n.detail-spr{position:absolute;left:50%;bottom:6%;transform:translateX(-50%);height:82%;\n  filter:drop-shadow(0 24px 30px rgba(0,0,0,.6));animation:heroBob 5s ease-in-out infinite;z-index:1;}\n.detail-glow{position:absolute;left:50%;bottom:2%;transform:translateX(-50%);width:80%;height:70%;\n  border-radius:50%;background:radial-gradient(closest-side,rgba(150,200,255,.4),transparent);z-index:0;}\n.detail-text{position:absolute;left:0;right:0;bottom:0;z-index:2;padding:0 6vw 5vh;text-align:center;\n  background:linear-gradient(0deg,rgba(6,10,23,.95) 40%,transparent);}\n.detail-text h2{font-family:var(--ui);letter-spacing:.12em;font-size:min(8vw,34px);margin:.1em;text-transform:uppercase;}\n.detail-text .role{color:var(--amber);font-style:italic;font-size:17px;margin-bottom:.5em;}\n.detail-text .power{color:var(--frost-dim);font-size:16px;line-height:1.5;max-width:520px;margin:.4em auto 1.1em;}\n.detail-back{position:absolute;top:4vh;left:4vw;z-index:3;}\n\n#world{background:#060a17;}\n#stage{position:absolute;inset:0;overflow:hidden;cursor:pointer;}\n/* cinematic camera: pans + zooms the whole scene (bg + actors + bubbles) */\n#cam{position:absolute;inset:0;transform-origin:50% 62%;will-change:transform;\n  transition:transform 1.7s cubic-bezier(.33,0,.2,1);}\n#bg{position:absolute;inset:-4%;background:center/cover no-repeat;\n  transition:opacity 1s ease;animation:kenburns 44s ease-in-out infinite alternate;transform-origin:60% 55%;}\n@keyframes kenburns{from{transform:scale(1.06)}to{transform:scale(1.16) translate(-1.5%,-1%)}}\n#vignette{position:absolute;inset:0;pointer-events:none;\n  background:radial-gradient(120% 100% at 50% 42%,transparent 46%,rgba(6,10,23,.5) 82%,rgba(6,10,23,.92));}\n#fx{position:absolute;inset:0;pointer-events:none;}\n#env{position:absolute;inset:0;pointer-events:none;overflow:hidden;}\n\n/* -------- environment ambience layers -------- */\n.fog{position:absolute;left:-20%;right:-20%;height:60%;pointer-events:none;opacity:.5;\n  background:radial-gradient(60% 100% at 30% 60%,rgba(210,225,255,.16),transparent 70%),\n             radial-gradient(50% 100% at 75% 55%,rgba(200,220,255,.12),transparent 70%);\n  animation:fogDrift 26s linear infinite;}\n.fog.low{bottom:0;} .fog.mid{bottom:22%;opacity:.35;animation-duration:40s;}\n@keyframes fogDrift{from{transform:translateX(-8%)}to{transform:translateX(8%)}}\n.mote{position:absolute;width:5px;height:5px;border-radius:50%;pointer-events:none;\n  background:radial-gradient(circle,rgba(255,240,190,.95),transparent 65%);animation:moteFloat linear infinite;}\n@keyframes moteFloat{0%{transform:translateY(0) translateX(0);opacity:0}\n  10%{opacity:.9}90%{opacity:.9}100%{transform:translateY(-140px) translateX(20px);opacity:0}}\n.smoke{position:absolute;width:18px;height:18px;border-radius:50%;pointer-events:none;\n  background:radial-gradient(circle,rgba(220,220,225,.5),transparent 68%);animation:smokeRise ease-out infinite;}\n@keyframes smokeRise{0%{transform:translateY(0) scale(.5);opacity:0}\n  20%{opacity:.5}100%{transform:translateY(-120px) scale(2.4);opacity:0}}\n.bird{position:absolute;pointer-events:none;color:rgba(20,28,44,.75);font-size:16px;will-change:transform;}\n.bird i{display:inline-block;animation:flap .4s ease-in-out infinite;}\n@keyframes flap{0%,100%{transform:scaleY(1)}50%{transform:scaleY(.5)}}\n/* butterflies — living colour that wanders a scene (garden/forest/chamber) */\n.bfly{position:absolute;pointer-events:none;z-index:12;font-size:15px;will-change:transform;\n  filter:drop-shadow(0 2px 3px rgba(0,0,0,.28));animation:bflyPath var(--bfd,15s) ease-in-out infinite alternate;}\n.bfly i{display:inline-block;animation:bflyWing .26s ease-in-out infinite;}\n@keyframes bflyWing{0%,100%{transform:scaleX(1)}50%{transform:scaleX(.4)}}\n@keyframes bflyPath{0%{transform:translate(0,0)}20%{transform:translate(9vw,-7vh)}45%{transform:translate(20vw,3vh)}\n  70%{transform:translate(31vw,-5vh)}100%{transform:translate(44vw,1vh)}}\n/* drifting leaves / falling petals as free-floating DOM (thorn wood, forest) */\n.leaf{position:absolute;pointer-events:none;z-index:11;width:11px;height:11px;border-radius:0 65% 65% 65%;\n  will-change:transform;opacity:.85;animation:leafFall var(--lfd,10s) linear infinite;}\n@keyframes leafFall{0%{transform:translateY(-8vh) rotate(0);opacity:0}12%{opacity:.85}\n  100%{transform:translateY(88vh) translateX(10vw) rotate(340deg);opacity:0}}\n#fgsnow{position:absolute;inset:0;pointer-events:none;opacity:0;transition:opacity 1.2s ease;\n  background-image:radial-gradient(2.5px 2.5px at 20% 30%,rgba(255,255,255,.9),transparent),\n    radial-gradient(3px 3px at 70% 60%,rgba(255,255,255,.85),transparent),\n    radial-gradient(2px 2px at 40% 80%,rgba(255,255,255,.8),transparent),\n    radial-gradient(3.5px 3.5px at 85% 20%,rgba(255,255,255,.9),transparent);\n  background-size:60% 60%;animation:fgFall 6s linear infinite;}\n#fgsnow.on{opacity:.55;}\n@keyframes fgFall{from{background-position:0 -40%,0 -60%,0 -50%,0 -30%}to{background-position:0 140%,0 160%,0 150%,0 130%}}\n\n/* -------- cinematic colour grade + key light (per scene mood) -------- */\n#grade{position:absolute;inset:0;pointer-events:none;mix-blend-mode:soft-light;opacity:.85;\n  transition:background 2.2s ease, opacity 2.2s ease;\n  background:radial-gradient(90% 70% at var(--kx,50%) var(--ky,18%),var(--key,rgba(255,240,210,.5)),transparent 60%),\n             linear-gradient(180deg,var(--gtop,rgba(120,150,210,.18)),transparent 45%,var(--gbot,rgba(10,16,36,.5)));}\n#grade.warm{--key:rgba(255,214,150,.6);--gtop:rgba(255,190,120,.14);--gbot:rgba(40,20,10,.5);--kx:50%;--ky:16%;}\n#grade.cold{--key:rgba(180,220,255,.5);--gtop:rgba(150,200,255,.2);--gbot:rgba(8,16,40,.62);--kx:50%;--ky:12%;}\n#grade.mystic{--key:rgba(150,255,210,.42);--gtop:rgba(120,220,255,.2);--gbot:rgba(10,20,44,.6);--kx:60%;--ky:14%;}\n#grade.bright{--key:rgba(255,244,210,.55);--gtop:rgba(210,230,255,.14);--gbot:rgba(30,30,50,.4);--kx:52%;--ky:14%;}\n/* -------- volumetric light shafts (god rays) -------- */\n#rays{position:absolute;inset:-10%;pointer-events:none;opacity:0;mix-blend-mode:screen;\n  transition:opacity 2.4s ease;transform:rotate(var(--rr,-18deg));transform-origin:70% 0;\n  background:repeating-linear-gradient(90deg,transparent 0,transparent 34px,rgba(255,240,205,.05) 40px,rgba(255,240,205,.11) 52px,transparent 66px,transparent 92px);\n  -webkit-mask-image:radial-gradient(80% 90% at 72% 0,#000,transparent 72%);mask-image:radial-gradient(80% 90% at 72% 0,#000,transparent 72%);\n  animation:rayShift 14s ease-in-out infinite alternate;}\n#rays.on{opacity:.9;} #rays.cool{--rr:-14deg;background:repeating-linear-gradient(90deg,transparent 0,transparent 40px,rgba(190,225,255,.06) 46px,rgba(190,225,255,.12) 58px,transparent 72px,transparent 100px);}\n@keyframes rayShift{from{transform:rotate(calc(var(--rr,-18deg) - 3deg)) translateX(-2%)}to{transform:rotate(calc(var(--rr,-18deg) + 3deg)) translateX(2%)}}\n/* -------- scene transition dip -------- */\n#dip{position:absolute;inset:0;pointer-events:none;z-index:48;opacity:0;transition:opacity .5s ease;\n  background:radial-gradient(120% 100% at 50% 40%,rgba(240,248,255,.9),rgba(20,30,60,.98));}\n#dip.show{opacity:1;} #dip.warmdip{background:radial-gradient(120% 100% at 50% 40%,rgba(30,16,8,.96),rgba(8,6,14,.99));}\n/* -------- frosty breath when a character speaks in the cold -------- */\n.breath{position:absolute;width:26px;height:16px;border-radius:50%;pointer-events:none;z-index:23;\n  background:radial-gradient(circle at 40% 45%,rgba(238,246,255,.8),transparent 70%);\n  animation:breathPuff 1.5s ease-out forwards;}\n@keyframes breathPuff{0%{opacity:0;transform:translate(0,0) scale(.4)}20%{opacity:.75}100%{opacity:0;transform:translate(18px,-16px) scale(1.9)}}\n\n/* -------- interactive discoveries (tap hidden things for lore + memories) -------- */\n#finds{position:absolute;inset:0;z-index:30;pointer-events:none;}\n.find{position:absolute;width:38px;height:38px;margin:-19px;border-radius:50%;pointer-events:auto;cursor:pointer;z-index:30;\n  display:flex;align-items:center;justify-content:center;font-size:19px;\n  background:radial-gradient(closest-side,rgba(180,225,255,.35),rgba(120,180,240,.12) 60%,transparent);\n  box-shadow:0 0 14px rgba(150,210,255,.5);animation:findPulse 2.4s ease-in-out infinite;\n  transition:opacity .4s ease,transform .25s ease;-webkit-tap-highlight-color:transparent;}\n.find:active{transform:scale(.86);}\n.find .glyph{filter:drop-shadow(0 1px 2px rgba(0,0,0,.6));opacity:.9;}\n.find .ring{position:absolute;inset:-4px;border-radius:50%;border:1.5px solid rgba(200,235,255,.6);animation:findRing 2.4s ease-out infinite;}\n@keyframes findPulse{0%,100%{box-shadow:0 0 12px rgba(150,210,255,.45)}50%{box-shadow:0 0 22px rgba(180,225,255,.85)}}\n@keyframes findRing{0%{transform:scale(.7);opacity:.8}100%{transform:scale(1.5);opacity:0}}\n.find.found{animation:none;background:radial-gradient(closest-side,rgba(120,200,150,.22),transparent 70%);box-shadow:none;opacity:.5;}\n.find.found .ring{display:none;}\n.find.found::after{content:\"✓\";position:absolute;right:-2px;bottom:-2px;font-size:11px;color:#8fe0a8;text-shadow:0 1px 2px #000;}\n.spark{position:absolute;width:6px;height:6px;border-radius:50%;pointer-events:none;z-index:33;\n  background:radial-gradient(circle,#fff,rgba(180,225,255,.9) 50%,transparent 70%);}\n/* discovery lore card */\n#findcard{position:absolute;inset:0;z-index:60;display:flex;align-items:center;justify-content:center;padding:8vw;\n  background:rgba(6,10,23,.55);opacity:0;pointer-events:none;transition:opacity .35s ease;}\n#findcard.show{opacity:1;pointer-events:auto;}\n#findcard .fc-inner{max-width:420px;text-align:center;padding:26px 24px;border-radius:20px;\n  background:linear-gradient(180deg,rgba(26,40,74,.96),rgba(12,18,40,.98));border:1px solid rgba(150,200,255,.35);\n  box-shadow:0 24px 60px rgba(0,0,0,.6),inset 0 1px 0 rgba(255,255,255,.12);transform:translateY(12px) scale(.96);transition:transform .35s cubic-bezier(.33,0,.2,1);}\n#findcard.show .fc-inner{transform:translateY(0) scale(1);}\n#findcard .fc-ic{font-size:40px;margin-bottom:8px;filter:drop-shadow(0 3px 8px rgba(0,0,0,.6));}\n#findcard .fc-name{font-family:var(--ui);font-size:16px;letter-spacing:.06em;color:var(--brand2,#e5399b);margin-bottom:10px;}\n#app[data-tale=\"snow_queen\"] #findcard .fc-name{color:#9fd0ff;}\n#findcard .fc-text{font-family:var(--body);font-size:16px;line-height:1.55;color:var(--frost);}\n#findcard .fc-foot{margin-top:16px;font-family:var(--ui);font-size:10px;letter-spacing:.16em;text-transform:uppercase;color:var(--frost-dim);}\n/* memories counter chip */\n.findchip{position:absolute;top:calc(8px + env(safe-area-inset-top));left:50%;transform:translateX(-50%);z-index:12;\n  display:none;align-items:center;gap:6px;padding:5px 12px;border-radius:20px;pointer-events:none;\n  font-family:var(--ui);font-size:12px;letter-spacing:.06em;color:var(--frost);\n  background:rgba(14,24,50,.6);border:1px solid rgba(150,200,255,.3);box-shadow:0 4px 12px rgba(0,0,0,.4);\n  opacity:0;transition:opacity .5s ease;}\n.findchip.on{display:flex;} .findchip.show{opacity:1;} .findchip .fi{color:#9fd0ff;}\n.findchip.ding{animation:chipDing .6s ease;} @keyframes chipDing{0%,100%{transform:translateX(-50%) scale(1)}40%{transform:translateX(-50%) scale(1.18)}}\n\n/* -------- actors: body carries behaviour gestures, .breathe carries the living idle, img carries locomotion -------- */\n.actor{position:absolute;bottom:8%;height:34%;pointer-events:auto;cursor:pointer;\n  transform:translateX(-50%);transform-origin:bottom center;\n  filter:drop-shadow(0 12px 14px rgba(0,0,0,.5));\n  transition:left 1.35s cubic-bezier(.42,0,.2,1),bottom 1.35s cubic-bezier(.42,0,.2,1),opacity .6s,filter .8s ease;}\n.actor .body{height:100%;transform-origin:bottom center;}\n/* a living idle: gentle breath + slow weight-shift, desynced per actor via --bd / --bdelay */\n.actor .breathe{height:100%;transform-origin:bottom center;will-change:transform;\n  animation:aLive var(--bd,4.6s) ease-in-out var(--bdelay,0s) infinite;}\n.actor img{height:100%;display:block;}\n.actor.walking .breathe,.actor.running .breathe{animation:none;}\n.actor.walking img{animation:walkBob .5s ease-in-out infinite;}\n.actor.running img{animation:walkBob .3s ease-in-out infinite;}\n.actor.running{transition:left .85s cubic-bezier(.3,0,.3,1);}\n.actor.face-left{transform:translateX(-50%) scaleX(-1);}\n@keyframes aLive{0%{transform:translateY(0) scaleY(1) scaleX(1) rotate(0)}\n  22%{transform:translateY(-.5%) scaleY(1.014) scaleX(.995) rotate(.45deg)}\n  50%{transform:translateY(-.15%) scaleY(1.004) scaleX(1) rotate(0)}\n  73%{transform:translateY(-.6%) scaleY(1.016) scaleX(.994) rotate(-.5deg)}\n  100%{transform:translateY(0) scaleY(1) scaleX(1) rotate(0)}}\n@keyframes walkBob{0%,100%{transform:translateY(0) rotate(-1.5deg)}50%{transform:translateY(-3%) rotate(1.5deg)}}\n/* emotion posture held while speaking (on .breathe, overrides the neutral idle) */\n.actor .breathe.pos-sad{animation:aSad 4.4s ease-in-out infinite;}\n.actor .breathe.pos-bold{animation:aBold 3.6s ease-in-out infinite;}\n.actor .breathe.pos-cold{animation:aCold 5.4s ease-in-out infinite;}\n.actor .breathe.pos-worried{animation:aWorried 3.3s ease-in-out infinite;}\n.actor .breathe.pos-tender{animation:aTender 4.6s ease-in-out infinite;}\n@keyframes aSad{0%,100%{transform:translateY(.7%) scaleY(.966) rotate(-1deg)}50%{transform:translateY(1.1%) scaleY(.958) rotate(-1.5deg)}}\n@keyframes aBold{0%,100%{transform:translateY(-.5%) scaleY(1.02) rotate(0)}50%{transform:translateY(-.95%) scaleY(1.03) rotate(.3deg)}}\n@keyframes aCold{0%,100%{transform:translateY(0) scaleY(1.002) rotate(.35deg)}50%{transform:translateY(-.1%) scaleY(1.004) rotate(-.35deg)}}\n@keyframes aWorried{0%,100%{transform:translateY(.2%) scaleY(.99) rotate(1.3deg)}50%{transform:translateY(-.25%) scaleY(1.006) rotate(-1.3deg)}}\n@keyframes aTender{0%,100%{transform:translateY(0) scaleY(1.006) rotate(-.9deg)}50%{transform:translateY(-.55%) scaleY(1.016) rotate(.9deg)}}\n/* a brief lean when the wind gusts (ordered last so it wins over posture) */\n.actor .breathe.gust{animation:aGust 1.1s ease-out;}\n@keyframes aGust{0%,100%{transform:rotate(0) translateY(0)}28%{transform:rotate(3deg) translateY(-1%)}70%{transform:rotate(1.3deg)}}\n.actor.player{z-index:20;}\n/* per-scene character lighting (sits the cast in the scene's light) + mood rim on the speaker */\n#stage[data-light=\"cold\"] .actor img{filter:brightness(.96) saturate(.9) contrast(1.03);}\n#stage[data-light=\"warm\"] .actor img{filter:brightness(1.05) saturate(1.07);}\n#stage[data-light=\"mystic\"] .actor img{filter:brightness(.98) saturate(.95) contrast(1.04);}\n#stage[data-light=\"bright\"] .actor img{filter:brightness(1.04) saturate(1.03);}\n.actor.speaking{filter:drop-shadow(0 0 22px var(--rim,rgba(255,220,150,.6))) drop-shadow(0 12px 16px rgba(0,0,0,.55));z-index:22;}\n/* contact shadow that grounds the character to the floor, breathing with them */\n.actor .shadow{position:absolute;left:50%;bottom:1.5%;transform:translateX(-50%);width:56%;height:7%;z-index:-1;\n  background:radial-gradient(closest-side,rgba(0,0,0,.5),transparent 78%);filter:blur(2px);pointer-events:none;\n  animation:aShadow var(--bd,4.6s) ease-in-out var(--bdelay,0s) infinite;}\n@keyframes aShadow{0%,100%{transform:translateX(-50%) scale(1);opacity:.5}50%{transform:translateX(-50%) scale(.93);opacity:.42}}\n.actor.enter{animation:actorEnter 1s cubic-bezier(.33,0,.2,1);}\n@keyframes actorEnter{from{opacity:0;transform:translateX(-50%) translateY(9%) scale(.92)}to{opacity:1;transform:translateX(-50%) translateY(0) scale(1)}}\n.actor .tag{position:absolute;bottom:100%;left:50%;transform:translateX(-50%);margin-bottom:6px;\n  font-family:var(--ui);font-size:11px;letter-spacing:.08em;color:var(--frost);text-transform:uppercase;\n  white-space:nowrap;text-shadow:0 2px 6px #000;opacity:0;transition:opacity .3s;pointer-events:none;}\n.actor:hover .tag{opacity:.9;}\n.actor.face-left .tag{transform:translateX(-50%) scaleX(-1);}\n.actor .halo{position:absolute;left:50%;bottom:-4%;transform:translateX(-50%);width:80%;height:24%;border-radius:50%;\n  background:radial-gradient(closest-side,rgba(255,220,150,.5),transparent);opacity:0;transition:opacity .4s;\n  animation:haloPulse 2.6s ease-in-out infinite;}\n.actor.interest .halo{opacity:1;}\n@keyframes haloPulse{0%,100%{opacity:.35}50%{opacity:.75}}\n\n/* -------- behavior animation library (played on .body) -------- */\n.b-look{animation:bLook 2.6s ease-in-out;} @keyframes bLook{0%,100%{transform:rotate(0)}25%{transform:rotate(-3.5deg)}60%{transform:rotate(3.5deg)}}\n.b-sway{animation:bSway 3.2s ease-in-out;} @keyframes bSway{0%,100%{transform:translateX(0) rotate(0)}50%{transform:translateX(2%) rotate(1.6deg)}}\n.b-wave{animation:bWave 1.1s ease-in-out;} @keyframes bWave{0%,100%{transform:rotate(0)}20%{transform:rotate(-7deg)}40%{transform:rotate(4deg)}60%{transform:rotate(-6deg)}80%{transform:rotate(3deg)}}\n.b-nod{animation:bNod 1s ease-in-out;} @keyframes bNod{0%,100%{transform:translateY(0) scaleY(1)}50%{transform:translateY(3%) scaleY(.96)}}\n.b-shake{animation:bShake 1s ease-in-out;} @keyframes bShake{0%,100%{transform:rotate(0)}25%{transform:rotate(4deg)}75%{transform:rotate(-4deg)}}\n.b-hop{animation:bHop .75s ease-out;} @keyframes bHop{0%,100%{transform:translateY(0)}40%{transform:translateY(-13%)}}\n.b-shiver{animation:bShiver .5s linear 2;} @keyframes bShiver{0%,100%{transform:translateX(0)}25%{transform:translateX(-1.6%)}75%{transform:translateX(1.6%)}}\n.b-point{animation:bPoint 1.3s ease-in-out;} @keyframes bPoint{0%,100%{transform:rotate(0) translateX(0)}45%{transform:rotate(-6deg) translateX(3%)}}\n.b-cheer{animation:bCheer 1.1s ease-in-out;} @keyframes bCheer{0%,100%{transform:translateY(0) rotate(0)}30%{transform:translateY(-11%) rotate(-4deg)}62%{transform:translateY(-6%) rotate(4deg)}}\n.b-bow{animation:bBow 1.4s ease-in-out;} @keyframes bBow{0%,100%{transform:rotate(0) scaleY(1)}45%{transform:rotate(0) scaleY(.86) translateY(6%)}}\n.b-back{animation:bBack 1s ease-in-out;} @keyframes bBack{0%,100%{transform:translateX(0)}50%{transform:translateX(-4%) rotate(2deg)}}\n/* an embrace: lean in, hold, settle — used for the reunion */\n.b-hug{animation:bHug 2.2s ease-in-out;} @keyframes bHug{0%{transform:translateX(0) rotate(0)}22%{transform:translateX(6%) rotate(4deg) scaleY(.98)}60%{transform:translateX(5%) rotate(3deg) scaleY(.98)}100%{transform:translateX(0) rotate(0)}}\n/* kneel/collapse in grief or exhaustion */\n.b-kneel{animation:bKneel 1.6s ease-in-out;} @keyframes bKneel{0%,100%{transform:translateY(0) scaleY(1)}45%{transform:translateY(9%) scaleY(.9)}}\n/* speaking: a gentle, slightly irregular head-and-shoulders motion (not a metronome) */\n.talking{animation:bTalk .9s ease-in-out infinite;}\n@keyframes bTalk{0%{transform:translateY(0) rotate(0)}20%{transform:translateY(-1.2%) rotate(.5deg)}42%{transform:translateY(-.3%) rotate(-.3deg)}\n  64%{transform:translateY(-1.4%) rotate(.4deg)}82%{transform:translateY(-.5%) rotate(-.2deg)}100%{transform:translateY(0) rotate(0)}}\n/* looping activities */\n.act-sweep{animation:actSweep 1.7s ease-in-out infinite;} @keyframes actSweep{0%,100%{transform:rotate(-2.5deg)}50%{transform:rotate(3deg)}}\n.act-cook{animation:actCook 1.5s ease-in-out infinite;} @keyframes actCook{0%,100%{transform:translateY(0) rotate(-1deg)}50%{transform:translateY(-1.5%) rotate(1.5deg)}}\n.act-skate{animation:actSkate 1.5s ease-in-out infinite;} @keyframes actSkate{0%,100%{transform:translateX(-2.5%) rotate(-2.5deg)}50%{transform:translateX(2.5%) rotate(2.5deg)}}\n.act-work{animation:actWork 1.3s ease-in-out infinite;} @keyframes actWork{0%,100%{transform:translateY(0)}50%{transform:translateY(-2%) rotate(1deg)}}\n.act-read{animation:actRead 4s ease-in-out infinite;} @keyframes actRead{0%,100%{transform:rotate(-1deg)}50%{transform:rotate(1deg)}}\n.act-sky{animation:actSky 5s ease-in-out infinite;} @keyframes actSky{0%,100%{transform:rotate(0)}50%{transform:rotate(-2deg) translateY(-1%)}}\n.act-play{animation:actPlay 1.1s ease-in-out infinite;} @keyframes actPlay{0%,100%{transform:translateY(0) rotate(-3deg)}50%{transform:translateY(-10%) rotate(3deg)}}\n.act-carry{animation:actCarry 2.4s ease-in-out infinite;} @keyframes actCarry{0%,100%{transform:rotate(-1.5deg) translateY(0)}50%{transform:rotate(1.5deg) translateY(-1%)}}\n.act-chop{animation:actChop 1.2s ease-in-out infinite;} @keyframes actChop{0%,100%{transform:rotate(-6deg)}45%{transform:rotate(8deg)}}\n.act-knit{animation:actKnit 1.9s ease-in-out infinite;} @keyframes actKnit{0%,100%{transform:rotate(-1deg)}50%{transform:rotate(2deg)}}\n.act-glide{animation:actGlide 5s ease-in-out infinite;} @keyframes actGlide{0%,100%{transform:translateX(-1.5%)}50%{transform:translateX(1.5%)}}\n\n/* background \"extras\" — distant villagers/children who live in the scene */\n.actor.extra{height:23%;opacity:.9;bottom:11%;z-index:6;filter:drop-shadow(0 8px 10px rgba(0,0,0,.4));}\n.actor.extra.far{height:18%;opacity:.75;bottom:15%;z-index:5;}\n.actor.extra .tag,.actor.extra .halo{display:none;}\n.snowball{position:absolute;width:12px;height:12px;border-radius:50%;z-index:16;pointer-events:none;\n  background:radial-gradient(circle at 40% 35%,#fff,#cfe0f5);box-shadow:0 0 8px rgba(255,255,255,.7);}\n\n/* cinematic mode hides the Continue chrome so the world tells the story */\n#narration.cine .narr-foot{display:none;}\n#narration.cine .narr-text{text-align:center;font-style:italic;}\n@media (prefers-reduced-motion:reduce){ #cam{transition:none} .actor .body,.actor img,.actor .breathe,.actor .shadow{animation:none!important} #rays,#grade{animation:none!important} }\n\n.bubble{position:absolute;z-index:40;max-width:min(72vw,320px);\n  transform:translate(-50%,-100%) scale(.6);opacity:0;transform-origin:bottom center;\n  transition:transform .35s cubic-bezier(.34,1.56,.64,1),opacity .3s;pointer-events:none;}\n.bubble.show{transform:translate(-50%,-100%) scale(1);opacity:1;}\n.bubble .box{position:relative;padding:.7em 1em;border-radius:16px;\n  background:linear-gradient(180deg,#fbf3df,#efe0bd);color:var(--parch-ink);\n  font-size:16px;line-height:1.35;font-family:var(--body);\n  box-shadow:0 10px 26px rgba(0,0,0,.5),inset 0 1px 0 rgba(255,255,255,.7);border:1px solid rgba(120,90,40,.35);}\n.bubble .box::after{content:\"\";position:absolute;top:100%;left:50%;transform:translateX(-50%);\n  border:9px solid transparent;border-top-color:#efe0bd;}\n.bubble .who{display:block;font-family:var(--ui);font-size:10px;letter-spacing:.1em;\n  text-transform:uppercase;color:var(--amber-deep);margin-bottom:.15em;}\n.bubble.think .box{font-style:italic;color:#6a5a3a;}\n\n.exit{position:absolute;z-index:15;bottom:30%;cursor:pointer;display:flex;flex-direction:column;align-items:center;gap:4px;\n  transform:translateX(-50%);transition:transform .25s,opacity .5s;}\n.exit:hover{transform:translateX(-50%) translateY(-4px);}\n.exit .orb{width:44px;height:44px;border-radius:50%;\n  background:radial-gradient(circle at 40% 35%,rgba(255,240,200,.95),rgba(255,200,110,.5) 60%,transparent 72%);\n  box-shadow:0 0 26px rgba(255,210,130,.7);animation:orbPulse 2.4s ease-in-out infinite;\n  display:flex;align-items:center;justify-content:center;font-size:20px;color:#3a2a10;}\n@keyframes orbPulse{0%,100%{transform:scale(1);opacity:.85}50%{transform:scale(1.14);opacity:1}}\n.exit .lbl{font-family:var(--ui);font-size:10px;letter-spacing:.08em;text-transform:uppercase;\n  color:var(--frost);text-shadow:0 2px 6px #000;white-space:nowrap;}\n\n.hotspot{position:absolute;z-index:14;width:38px;height:38px;cursor:pointer;transform:translate(-50%,-50%);}\n.hotspot .spark{position:absolute;inset:0;border-radius:50%;\n  background:radial-gradient(circle,rgba(180,230,255,.9),transparent 65%);animation:sparkPulse 2.2s ease-in-out infinite;}\n.hotspot::after{content:\"✦\";position:absolute;inset:0;display:flex;align-items:center;justify-content:center;\n  color:#eaf6ff;font-size:15px;text-shadow:0 0 8px #9fd4ff;animation:sparkPulse 2.2s ease-in-out infinite;}\n@keyframes sparkPulse{0%,100%{transform:scale(.85);opacity:.5}50%{transform:scale(1.2);opacity:1}}\n\n#hud{position:absolute;top:0;left:0;right:0;z-index:50;padding:env(safe-area-inset-top) 0 0;\n  display:flex;align-items:flex-start;justify-content:space-between;pointer-events:none;}\n.hud-left{display:flex;align-items:center;gap:10px;padding:14px;pointer-events:auto;}\n.portrait{width:50px;height:50px;border-radius:50%;overflow:hidden;flex:0 0 auto;\n  background:rgba(20,32,64,.7);border:2px solid var(--amber);box-shadow:0 4px 14px rgba(0,0,0,.5);position:relative;}\n.portrait img{position:absolute;width:180%;left:-40%;top:8%;}\n.hud-who .nm{font-family:var(--ui);font-size:13px;letter-spacing:.08em;text-transform:uppercase;text-shadow:0 2px 6px #000;}\n.hud-who .loc{font-style:italic;font-size:12px;color:var(--frost-dim);text-shadow:0 2px 6px #000;}\n.hud-right{display:flex;gap:8px;padding:14px;pointer-events:auto;flex-wrap:wrap;justify-content:flex-end;}\n.iconbtn{width:42px;height:42px;border-radius:50%;cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:18px;\n  background:rgba(14,24,52,.66);border:1px solid rgba(150,190,255,.3);color:var(--frost);\n  box-shadow:0 4px 14px rgba(0,0,0,.4);transition:filter .2s,transform .15s;position:relative;}\n.iconbtn:hover{filter:brightness(1.3);transform:translateY(-1px);}\n.iconbtn:active{transform:scale(.94);}\n.iconbtn .lc{position:absolute;bottom:-3px;right:-3px;font-family:var(--ui);font-size:8px;letter-spacing:.02em;\n  background:var(--amber);color:#12203c;border-radius:8px;padding:1px 4px;}\n\n/* objective / chapter banner */\n#objective{position:absolute;top:calc(70px + env(safe-area-inset-top));left:50%;transform:translateX(-50%);\n  z-index:46;max-width:min(90vw,520px);text-align:center;background:rgba(8,14,30,.62);\n  border:1px solid rgba(150,190,255,.25);border-radius:14px;padding:.5em 1.1em;backdrop-filter:blur(4px);\n  box-shadow:0 8px 24px rgba(0,0,0,.4);opacity:0;transition:opacity .6s;pointer-events:none;}\n#objective.show{opacity:1;}\n#objective .ch{font-family:var(--ui);font-size:10px;letter-spacing:.16em;text-transform:uppercase;color:var(--amber);}\n#objective .goal{font-size:14px;color:var(--frost);margin-top:2px;}\n#objective .goal b{color:var(--amber);font-weight:normal;font-style:italic;}\n\n/* chapter card */\n#chaptercard{position:absolute;inset:0;z-index:80;display:flex;align-items:center;justify-content:center;flex-direction:column;\n  text-align:center;background:radial-gradient(120% 100% at 50% 40%,rgba(10,18,40,.7),rgba(6,10,23,.94));\n  opacity:0;pointer-events:none;transition:opacity 1s ease;padding:8vw;}\n#chaptercard.show{opacity:1;pointer-events:auto;}\n#chaptercard .cno{font-family:var(--ui);letter-spacing:.4em;font-size:13px;color:var(--amber);text-transform:uppercase;}\n#chaptercard .cttl{font-family:var(--ui);font-size:min(9vw,44px);letter-spacing:.06em;margin:.3em 0;\n  text-shadow:0 0 40px rgba(150,200,255,.4);}\n#chaptercard .rule{width:120px;height:1px;margin:.4em auto;background:linear-gradient(90deg,transparent,var(--amber),transparent);}\n#chaptercard .ctap{margin-top:1.4em;font-style:italic;color:var(--frost-dim);font-size:13px;animation:pulse 2s ease-in-out infinite;}\n@keyframes pulse{0%,100%{opacity:.4}50%{opacity:1}}\n\n/* narration bar (audiobook) */\n#narration{position:absolute;left:0;right:0;bottom:0;z-index:47;padding:16px 16px calc(20px + env(safe-area-inset-bottom));\n  background:linear-gradient(0deg,rgba(6,10,23,.94) 55%,rgba(6,10,23,.4) 85%,transparent);\n  transform:translateY(120%);transition:transform .5s cubic-bezier(.4,0,.2,1);}\n#narration.show{transform:translateY(0);}\n.narr-inner{max-width:720px;margin:0 auto;}\n.narr-who{font-family:var(--ui);font-size:11px;letter-spacing:.16em;text-transform:uppercase;color:var(--amber);margin-bottom:.35em;}\n.narr-text{font-size:min(4.8vw,20px);line-height:1.5;color:var(--frost);min-height:2.6em;}\n.narr-foot{display:flex;justify-content:space-between;align-items:center;margin-top:.7em;gap:8px;}\n.narr-hint{font-style:italic;font-size:12px;color:var(--frost-dim);}\n.narr-actions{display:flex;gap:8px;}\n.miniic{width:36px;height:36px;border-radius:50%;cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:15px;\n  background:rgba(20,34,66,.8);border:1px solid rgba(150,190,255,.3);color:var(--frost);}\n.narr-cont{padding:.5em 1.2em;border-radius:30px;cursor:pointer;font-family:var(--ui);font-size:12px;letter-spacing:.12em;\n  text-transform:uppercase;color:#12203c;background:linear-gradient(180deg,#ffe9b8,#e8b25a);\n  box-shadow:0 4px 14px rgba(0,0,0,.4);display:inline-flex;align-items:center;gap:.4em;animation:pulse 2.4s ease-in-out infinite;}\n\n/* dialogue advance hint + input */\n#dlgadv{position:absolute;left:0;right:0;bottom:calc(20px + env(safe-area-inset-bottom));z-index:47;text-align:center;\n  opacity:0;transition:opacity .4s;pointer-events:none;}\n#dlgadv.show{opacity:1;}\n#dlgadv span{display:inline-flex;align-items:center;gap:.4em;font-style:italic;font-size:13px;color:var(--frost-dim);\n  background:rgba(6,10,23,.5);padding:.4em 1em;border-radius:20px;}\n\n#promptbar{position:absolute;left:0;right:0;bottom:0;z-index:48;padding:12px 14px calc(14px + env(safe-area-inset-bottom));\n  display:flex;gap:8px;align-items:center;background:linear-gradient(0deg,rgba(6,10,23,.8),transparent);\n  transform:translateY(140%);transition:transform .5s cubic-bezier(.4,0,.2,1);}\n#promptbar.show{transform:translateY(0);}\n#promptbar input{flex:1;min-width:0;padding:.8em 1.1em;border-radius:24px;background:rgba(10,18,40,.85);\n  border:1px solid rgba(150,190,255,.35);color:var(--frost);font-family:var(--body);font-size:16px;outline:none;}\n#promptbar input::placeholder{color:var(--frost-dim);font-style:italic;}\n#promptbar .mic.live{background:linear-gradient(180deg,#ff9db0,#e8536f);color:#fff;border-color:#ff9db0;animation:micPulse 1.2s ease-in-out infinite;}\n@keyframes micPulse{0%,100%{box-shadow:0 0 0 0 rgba(232,83,111,.5)}50%{box-shadow:0 0 0 10px rgba(232,83,111,0)}}\n.talkbtn{position:absolute;right:14px;bottom:calc(70px + env(safe-area-inset-bottom));z-index:48;}\n\n/* player-turn (the player performs their own line) */\n#playerturn{position:absolute;left:0;right:0;bottom:0;z-index:58;padding:16px 16px calc(18px + env(safe-area-inset-bottom));\n  background:linear-gradient(0deg,rgba(6,10,23,.96) 60%,rgba(6,10,23,.4) 88%,transparent);\n  transform:translateY(120%);transition:transform .45s cubic-bezier(.34,1.4,.64,1);}\n#playerturn.show{transform:translateY(0);}\n.pt-card{max-width:560px;margin:0 auto;text-align:center;}\n.pt-turn{font-family:var(--ui);font-size:11px;letter-spacing:.18em;text-transform:uppercase;color:var(--amber);}\n.pt-role{font-size:14px;color:var(--frost-dim);margin-top:2px;}\n.pt-role b{color:var(--frost);font-weight:normal;font-family:var(--ui);letter-spacing:.06em;}\n.pt-sug{font-style:italic;font-size:min(4.6vw,18px);color:var(--frost);margin:.5em auto .3em;max-width:480px;opacity:.85;}\n.pt-mic{width:64px;height:64px;border-radius:50%;margin:.5em auto .2em;display:flex;align-items:center;justify-content:center;\n  font-size:26px;cursor:pointer;color:#12203c;background:linear-gradient(180deg,#ffe9b8,#e8b25a);\n  box-shadow:0 6px 20px rgba(0,0,0,.5),inset 0 1px 0 rgba(255,255,255,.6);transition:transform .15s;}\n.pt-mic:active{transform:scale(.94);}\n.pt-mic.live{background:linear-gradient(180deg,#ff9db0,#e8536f);color:#fff;animation:micPulse 1.1s ease-in-out infinite;}\n.pt-hint{font-style:italic;font-size:13px;color:var(--frost-dim);min-height:1.2em;margin-bottom:.5em;}\n/* live recording feedback: pulsing dot + timer + waveform */\n.pt-rec{display:none;align-items:center;justify-content:center;gap:.5em;margin:.15em 0 .1em;\n  font-family:var(--ui);font-weight:700;font-size:13px;letter-spacing:.04em;color:#ff8fb0;font-variant-numeric:tabular-nums;}\n.pt-rec.show{display:flex;}\n.pt-dot{width:9px;height:9px;border-radius:50%;background:#ff416c;box-shadow:0 0 8px #ff416c;animation:recBlink 1s steps(2,start) infinite;}\n@keyframes recBlink{50%{opacity:.25;}}\n.pt-wave{display:none;width:100%;max-width:480px;height:44px;margin:.1em auto .3em;border-radius:12px;\n  background:rgba(10,18,40,.6);border:1px solid rgba(160,140,230,.28);}\n.pt-wave.show{display:block;}\n#ptInput{width:100%;padding:.7em 1.1em;border-radius:22px;background:rgba(10,18,40,.85);border:1px solid rgba(150,190,255,.35);\n  color:var(--frost);font-family:var(--body);font-size:16px;outline:none;margin-bottom:.5em;}\n#ptInput::placeholder{color:var(--frost-dim);font-style:italic;}\n.pt-take{display:none;gap:8px;justify-content:center;margin:.2em 0 .6em;}\n.pt-take.show{display:flex;}\n.pt-tbtn{display:inline-flex;align-items:center;gap:.4em;min-height:40px;padding:.4em 1em;border-radius:20px;cursor:pointer;\n  font-family:var(--ui);font-weight:600;font-size:12px;color:var(--frost);background:rgba(255,255,255,.08);\n  border:1px solid rgba(160,140,230,.4);}\n.pt-tbtn:active{transform:scale(.96);}\n.pt-mic.rec{background:linear-gradient(180deg,#ff6a8a,#e5399b)!important;color:#fff;animation:micPulse 1s ease-in-out infinite;}\n\n/* ambient (living-world) speech: softer, auto-dismissing */\n.bubble.ambient .box{background:linear-gradient(180deg,#eef6ff,#d7e6fb);color:#26364f;opacity:.96;}\n.bubble.ambient .box::after{border-top-color:#d7e6fb;}\n\n/* ice puzzle */\n#puzzle{position:absolute;inset:0;z-index:82;display:flex;flex-direction:column;align-items:center;justify-content:center;\n  gap:18px;background:radial-gradient(120% 100% at 50% 40%,rgba(30,60,110,.5),rgba(6,10,23,.92));\n  opacity:0;pointer-events:none;transition:opacity .6s;padding:6vw;text-align:center;}\n#puzzle.show{opacity:1;pointer-events:auto;}\n#puzzle h3{font-family:var(--ui);letter-spacing:.1em;font-size:min(6vw,24px);margin:0;}\n#puzzle p{color:var(--frost-dim);font-style:italic;margin:0;max-width:460px;}\n.pz-target{display:flex;gap:6px;flex-wrap:wrap;justify-content:center;min-height:52px;}\n.pz-slot{width:40px;height:48px;border-radius:8px;border:1px dashed rgba(150,200,255,.4);\n  display:flex;align-items:center;justify-content:center;font-family:var(--ui);font-size:22px;color:var(--frost);\n  background:rgba(140,190,255,.08);}\n.pz-slot.filled{border-style:solid;background:linear-gradient(180deg,rgba(200,230,255,.5),rgba(140,190,255,.3));color:#12203c;}\n.pz-pool{display:flex;gap:8px;flex-wrap:wrap;justify-content:center;max-width:560px;}\n.pz-shard{width:44px;height:52px;border-radius:8px;cursor:pointer;display:flex;align-items:center;justify-content:center;\n  font-family:var(--ui);font-size:22px;color:#12203c;background:linear-gradient(180deg,#dff0ff,#a9cff5);\n  box-shadow:0 6px 16px rgba(0,0,0,.4),inset 0 1px 0 rgba(255,255,255,.7);transition:transform .15s,opacity .3s;}\n.pz-shard:hover{transform:translateY(-3px);}\n.pz-shard.used{opacity:.25;pointer-events:none;}\n\n#sheet{position:absolute;inset:0;z-index:60;opacity:0;pointer-events:none;background:rgba(6,10,23,.6);transition:opacity .4s;backdrop-filter:blur(3px);}\n#sheet.on{opacity:1;pointer-events:auto;}\n.parch{position:absolute;top:50%;left:50%;transform:translate(-50%,-46%) scale(.94);width:min(92vw,560px);max-height:82vh;\n  overflow:hidden;border-radius:16px;background:linear-gradient(180deg,#f3e7c8,#e6d3a6);color:var(--parch-ink);\n  box-shadow:0 30px 70px rgba(0,0,0,.6),inset 0 0 60px rgba(150,110,50,.2);\n  border:1px solid rgba(120,90,40,.5);transition:transform .4s cubic-bezier(.34,1.4,.64,1);display:flex;flex-direction:column;}\n#sheet.on .parch{transform:translate(-50%,-50%) scale(1);}\n.parch-tabs{display:flex;border-bottom:2px solid rgba(120,90,40,.35);flex:0 0 auto;}\n.parch-tabs button{flex:1;padding:1em .3em;background:none;border:none;cursor:pointer;font-family:var(--ui);font-size:12px;\n  letter-spacing:.1em;text-transform:uppercase;color:#7a5f30;position:relative;}\n.parch-tabs button.sel{color:var(--parch-ink);}\n.parch-tabs button.sel::after{content:\"\";position:absolute;left:20%;right:20%;bottom:-2px;height:2px;background:var(--amber-deep);}\n.parch-body{padding:1.2em 1.4em;overflow-y:auto;flex:1;}\n.parch-body h4{font-family:var(--ui);letter-spacing:.08em;text-transform:uppercase;font-size:14px;margin:.2em 0 .8em;color:#5a441f;}\n.entry{margin:0 0 .9em;padding:.7em .9em;border-radius:10px;background:rgba(255,255,255,.35);border:1px solid rgba(120,90,40,.25);}\n.entry .h{font-family:var(--ui);font-size:13px;letter-spacing:.04em;color:#4a3714;}\n.entry .d{font-size:14px;color:#5a4a2c;margin-top:.2em;font-style:italic;}\n.empty{font-style:italic;color:#8a744a;text-align:center;padding:2em 0;}\n.relics{display:flex;flex-wrap:wrap;gap:12px;}\n.relic{width:calc(50% - 6px);border-radius:12px;overflow:hidden;background:rgba(255,255,255,.4);border:1px solid rgba(120,90,40,.3);text-align:center;padding-bottom:.6em;}\n.relic img{width:100%;aspect-ratio:1;object-fit:cover;background:#d8c69a;}\n.relic .rn{font-family:var(--ui);font-size:11px;letter-spacing:.06em;text-transform:uppercase;margin-top:.4em;color:#4a3714;}\n.relic .rd{font-size:12px;color:#6a5630;font-style:italic;padding:0 .6em;}\n#mapCanvas{width:100%;height:46vh;display:block;border-radius:10px;background:radial-gradient(120% 120% at 50% 0%,#dcc99b,#c9b184);}\n.map-hint{text-align:center;font-style:italic;color:#7a5f30;font-size:13px;margin-top:.6em;}\n.parch-close{position:absolute;top:8px;right:10px;z-index:2;width:34px;height:34px;border-radius:50%;border:none;cursor:pointer;font-size:18px;color:#4a3714;background:rgba(255,255,255,.4);}\n\n#toasts{position:absolute;top:0;left:0;right:0;z-index:70;display:flex;flex-direction:column;align-items:center;gap:8px;\n  padding-top:calc(120px + env(safe-area-inset-top));pointer-events:none;}\n.toast{display:flex;align-items:center;gap:10px;padding:.6em 1.1em;border-radius:30px;\n  background:linear-gradient(180deg,rgba(30,44,80,.95),rgba(14,24,52,.95));border:1px solid var(--amber);\n  box-shadow:0 10px 30px rgba(0,0,0,.5),0 0 24px rgba(255,200,120,.25);\n  transform:translateY(-24px);opacity:0;transition:transform .5s cubic-bezier(.34,1.4,.64,1),opacity .5s;}\n.toast.show{transform:translateY(0);opacity:1;}\n.toast .ic{font-size:20px;}\n.toast .tx b{font-family:var(--ui);font-size:11px;letter-spacing:.1em;text-transform:uppercase;color:var(--amber);display:block;}\n.toast .tx span{font-size:13px;color:var(--frost);}\n\n#ending{background:#050810;display:flex;align-items:center;justify-content:center;text-align:center;}\n#ending .in{max-width:620px;padding:6vw;z-index:2;}\n#ending h2{font-family:var(--ui);font-size:min(9vw,42px);letter-spacing:.08em;text-transform:uppercase;margin:.2em;text-shadow:0 0 40px rgba(150,200,255,.4);}\n#ending p{font-style:italic;color:var(--frost-dim);font-size:18px;line-height:1.6;margin:1em 0 1.6em;}\n#ending::after{content:\"\";position:absolute;inset:0;background:radial-gradient(100% 80% at 50% 40%,rgba(40,70,140,.3),transparent 70%);}\n\n#veil{position:absolute;inset:0;z-index:200;background:#060a17;display:flex;align-items:center;justify-content:center;\n  flex-direction:column;gap:1.4em;transition:opacity 1s ease;}\n#veil.gone{opacity:0;pointer-events:none;}\n.flake{width:46px;height:46px;animation:spin 3.4s linear infinite;opacity:.9;}\n@keyframes spin{to{transform:rotate(360deg)}}\n#veil .ld{font-family:var(--ui);letter-spacing:.3em;font-size:12px;color:var(--frost-dim);text-transform:uppercase;}\n\n.hidden{display:none !important;}\n/* the story auto-plays now — no Continue button, no tap-to-continue hint */\n#narrCont{display:none !important;} #dlgadv{display:none !important;}\n@media (max-width:520px){ .hero-card{width:74vw;height:60vh;} }\n\n/* ================= ALDAR KÖSE — warm steppe skin ================= */\n#app[data-tale=\"aldar_kose\"] .btn{background:linear-gradient(180deg,#ffd98a,#e08a2c 60%,#b85a1e);\n  box-shadow:0 6px 20px rgba(40,16,0,.5),inset 0 1px 0 rgba(255,240,200,.7),inset 0 -2px 6px rgba(120,50,0,.5);color:#3a1c06;}\n#app[data-tale=\"aldar_kose\"] .btn.ghost{background:linear-gradient(180deg,rgba(120,70,30,.5),rgba(60,32,12,.6));\n  color:#fdf1dc;border:1px solid rgba(232,164,58,.5);box-shadow:0 4px 16px rgba(30,14,0,.4);}\n#app[data-tale=\"aldar_kose\"] #vignette{background:radial-gradient(120% 100% at 50% 42%,transparent 48%,rgba(30,16,4,.4) 84%,rgba(24,12,3,.86));}\n#app[data-tale=\"aldar_kose\"] #narration{background:linear-gradient(0deg,rgba(28,16,6,.95) 55%,rgba(28,16,6,.4) 85%,transparent);}\n#app[data-tale=\"aldar_kose\"] #objective{background:rgba(40,22,8,.66);border-color:rgba(232,164,58,.35);}\n#app[data-tale=\"aldar_kose\"] .iconbtn{background:rgba(52,30,12,.7);border-color:rgba(232,164,58,.4);color:#fdf1dc;}\n#app[data-tale=\"aldar_kose\"] #promptbar,#app[data-tale=\"aldar_kose\"] #playerturn{background:linear-gradient(0deg,rgba(28,16,6,.95),transparent);}\n#app[data-tale=\"aldar_kose\"] #promptbar input,#app[data-tale=\"aldar_kose\"] #ptInput{background:rgba(46,26,10,.85);border-color:rgba(232,164,58,.4);color:#fdf1dc;}\n#app[data-tale=\"aldar_kose\"] #title::after{background:radial-gradient(120% 90% at 50% 8%,transparent 40%,rgba(30,16,4,.5) 78%,rgba(24,12,3,.95));}\n#app[data-tale=\"aldar_kose\"] #library{background:radial-gradient(130% 120% at 50% -10%,#3a2410,#160c04 72%);}\n#app[data-tale=\"aldar_kose\"] #select,#app[data-tale=\"aldar_kose\"] #detail{background:radial-gradient(120% 120% at 50% -10%,#3a2410,#160c04 72%);}\n#app[data-tale=\"aldar_kose\"] #ending{background:#160c04;}\n#app[data-tale=\"aldar_kose\"] #chaptercard{background:radial-gradient(120% 100% at 50% 40%,rgba(58,36,16,.7),rgba(22,12,4,.94));}\n/* a woven oyu-ornek ribbon along the top edge of the world */\n#app[data-tale=\"aldar_kose\"] #stage::before{content:\"\";position:absolute;top:0;left:0;right:0;height:14px;z-index:49;pointer-events:none;\n  background:\n    repeating-linear-gradient(90deg,transparent 0 10px,rgba(200,90,38,.9) 10px 14px,transparent 14px 24px),\n    repeating-linear-gradient(90deg,rgba(232,164,58,.9) 0 6px,transparent 6px 24px);\n  opacity:.55;}\n\n/* ================= ER-TÖSTIK — warm steppe / epic skin ================= */\n#app[data-tale=\"er_tostik\"] .btn{background:linear-gradient(180deg,#ffd98a,#e08a2c 60%,#a8481a);\n  box-shadow:0 6px 20px rgba(40,16,0,.5),inset 0 1px 0 rgba(255,240,200,.7),inset 0 -2px 6px rgba(120,50,0,.5);color:#3a1c06;}\n#app[data-tale=\"er_tostik\"] .btn.ghost{background:linear-gradient(180deg,rgba(120,70,30,.5),rgba(60,32,12,.6));\n  color:#fdf1dc;border:1px solid rgba(232,164,58,.5);box-shadow:0 4px 16px rgba(30,14,0,.4);}\n#app[data-tale=\"er_tostik\"] #vignette{background:radial-gradient(120% 100% at 50% 42%,transparent 48%,rgba(30,16,4,.4) 84%,rgba(24,12,3,.86));}\n#app[data-tale=\"er_tostik\"] #narration{background:linear-gradient(0deg,rgba(28,16,6,.95) 55%,rgba(28,16,6,.4) 85%,transparent);}\n#app[data-tale=\"er_tostik\"] #objective{background:rgba(40,22,8,.66);border-color:rgba(232,164,58,.35);}\n#app[data-tale=\"er_tostik\"] .iconbtn{background:rgba(52,30,12,.7);border-color:rgba(232,164,58,.4);color:#fdf1dc;}\n#app[data-tale=\"er_tostik\"] #promptbar,#app[data-tale=\"er_tostik\"] #playerturn{background:linear-gradient(0deg,rgba(28,16,6,.95),transparent);}\n#app[data-tale=\"er_tostik\"] #promptbar input,#app[data-tale=\"er_tostik\"] #ptInput{background:rgba(46,26,10,.85);border-color:rgba(232,164,58,.4);color:#fdf1dc;}\n#app[data-tale=\"er_tostik\"] #title::after{background:radial-gradient(120% 90% at 50% 8%,transparent 40%,rgba(30,16,4,.5) 78%,rgba(24,12,3,.95));}\n#app[data-tale=\"er_tostik\"] #library{background:radial-gradient(130% 120% at 50% -10%,#3a2410,#160c04 72%);}\n#app[data-tale=\"er_tostik\"] #select,#app[data-tale=\"er_tostik\"] #detail{background:radial-gradient(120% 120% at 50% -10%,#3a2410,#160c04 72%);}\n#app[data-tale=\"er_tostik\"] #ending{background:#160c04;}\n#app[data-tale=\"er_tostik\"] #chaptercard{background:radial-gradient(120% 100% at 50% 40%,rgba(58,36,16,.7),rgba(22,12,4,.94));}\n#app[data-tale=\"er_tostik\"] #stage::before{content:\"\";position:absolute;top:0;left:0;right:0;height:14px;z-index:49;pointer-events:none;\n  background:\n    repeating-linear-gradient(90deg,transparent 0 10px,rgba(200,90,38,.9) 10px 14px,transparent 14px 24px),\n    repeating-linear-gradient(90deg,rgba(232,164,58,.9) 0 6px,transparent 6px 24px);\n  opacity:.5;}\n\n/* ================= RIDDLE (wit puzzle) ================= */\n#riddle{position:absolute;inset:0;z-index:82;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:18px;\n  background:radial-gradient(120% 100% at 50% 40%,rgba(60,36,14,.6),rgba(18,10,3,.94));opacity:0;pointer-events:none;transition:opacity .6s;padding:7vw;text-align:center;}\n#riddle.show{opacity:1;pointer-events:auto;}\n#riddle .rd-tag{font-family:var(--ui);letter-spacing:.2em;text-transform:uppercase;font-size:12px;color:var(--amber);}\n#riddle h3{font-family:var(--ui);letter-spacing:.04em;font-size:min(6.4vw,26px);margin:0;color:var(--frost);max-width:640px;line-height:1.3;}\n#riddle .rd-opts{display:flex;flex-direction:column;gap:12px;width:min(90vw,460px);}\n.rd-opt{padding:.85em 1.2em;border-radius:14px;cursor:pointer;font-family:var(--body);font-size:17px;color:#3a1c06;\n  background:linear-gradient(180deg,#ffe6b0,#e6b264);border:1px solid rgba(120,70,20,.4);\n  box-shadow:0 6px 16px rgba(30,14,0,.4),inset 0 1px 0 rgba(255,255,255,.6);transition:transform .15s,filter .2s;}\n.rd-opt:hover{filter:brightness(1.06);transform:translateY(-2px);}\n.rd-opt.wrong{animation:rdShake .4s;filter:grayscale(.4) brightness(.85);}\n.rd-opt.right{background:linear-gradient(180deg,#bfe6a0,#7bbf5a);}\n@keyframes rdShake{0%,100%{transform:translateX(0)}25%{transform:translateX(-6px)}75%{transform:translateX(6px)}}"

export const CSS_SHELL = "/* ============================================================\n   JUST TO STUDY — Fairytale World · shell redesign (v2)\n   Restyles ONLY the surrounding interface (title, library,\n   character select, detail, ending, journal, HUD chrome).\n   The 2D world (#stage & children), covers, sprites, story,\n   dialogue, narration and in-world interactions are untouched.\n   Appended last so it layers over the base without removing it.\n   ============================================================ */\n:root{\n  --jt-violet:#874BF8; --jt-violet-deep:#6E37E6; --jt-violet-ink:#4A2AA6;\n  --jt-cyan:#0AAFFF; --jt-green:#00D441; --jt-orange:#FF631E; --jt-gold:#FFAD00;\n  --jt-ink:#1B1630; --jt-soft:#544F6B; --jt-muted:#8B87A0;\n  --jt-canvas:#F4F1FB; --jt-canvas2:#EBE6F7; --jt-surface:#FFFFFF; --jt-line:#EBE6F7;\n  --jt-shadow:0 20px 46px -26px rgba(74,42,166,.42);\n  --jt-shadow-lg:0 28px 64px -28px rgba(74,42,166,.55);\n  --jt-ease:cubic-bezier(.22,.61,.36,1);\n}\n\n/* gentle premium screen rise (world excluded so the stage never shifts) */\n.screen:not(#world){ transition:opacity .55s var(--jt-ease), transform .55s var(--jt-ease); transform:translateY(10px); }\n.screen:not(#world).on{ transform:translateY(0); }\n\n/* ---------- brand wordmark → speech-bubble mark ---------- */\n.jts .dot{ border-radius:11px 11px 11px 4px !important; background:linear-gradient(140deg,var(--jt-violet),var(--jt-violet-deep)) !important;\n  box-shadow:0 8px 20px -6px rgba(135,75,248,.6) !important; transform:rotate(-3deg); }\n.jts .wm{ font-weight:800 !important; letter-spacing:-.01em !important; }\n\n/* ---------- buttons ---------- */\n.btn{ border-radius:18px !important; font-weight:800 !important; letter-spacing:-.01em !important; text-transform:none !important;\n  background:linear-gradient(140deg,var(--jt-violet),var(--jt-violet-deep)) !important;\n  box-shadow:0 16px 32px -14px rgba(135,75,248,.62), inset 0 1px 0 rgba(255,255,255,.28) !important; }\n.btn:hover{ box-shadow:0 20px 40px -14px rgba(135,75,248,.7), inset 0 1px 0 rgba(255,255,255,.3) !important; }\n/* ghost: outline that works on light browsing screens */\n.btn.ghost{ background:var(--jt-surface) !important; color:var(--jt-violet-ink) !important;\n  border:1.5px solid var(--jt-line) !important; box-shadow:var(--jt-shadow) !important; backdrop-filter:none !important; }\n.btn.ghost:hover{ background:#fff !important; border-color:var(--jt-violet) !important; filter:none !important; }\n/* ghost on the dark immersive title stays frosted */\n#title .btn.ghost{ background:rgba(255,255,255,.12) !important; color:#fff !important;\n  border:1.5px solid rgba(255,255,255,.35) !important; backdrop-filter:blur(8px) !important; }\n\n/* language chips */\n.langchip{ border-radius:999px !important; font-weight:800 !important; letter-spacing:.02em !important;\n  background:rgba(255,255,255,.14) !important; border:1px solid rgba(255,255,255,.28) !important; color:#fff !important;\n  min-height:34px; display:flex; align-items:center; }\n.langchip.sel{ background:#fff !important; color:var(--jt-violet) !important; border-color:#fff !important; }\n/* on light screens (library/select) chips need contrast */\n#library .langchip, #select .langchip{ background:var(--jt-canvas2) !important; border-color:transparent !important; color:var(--jt-soft) !important; }\n#library .langchip.sel, #select .langchip.sel{ background:var(--jt-violet) !important; color:#fff !important; }\n\n/* ============================ TITLE (immersive) ============================ */\n#title::after{ background:\n  radial-gradient(130% 80% at 50% 120%, rgba(110,55,230,.72) 0%, rgba(74,42,166,.35) 42%, transparent 72%),\n  linear-gradient(180deg, rgba(12,7,32,.35) 0%, transparent 30%, rgba(12,7,32,.6) 100%) !important; }\n.title-kicker{ display:inline-flex; align-items:center; gap:.5em; letter-spacing:.18em !important; font-weight:800 !important;\n  color:#fff !important; opacity:.92 !important; background:rgba(255,255,255,.14); backdrop-filter:blur(6px);\n  padding:.5em 1em; border-radius:999px 999px 999px 6px; text-shadow:none !important; font-size:11px !important; }\n.title-name{ font-weight:900 !important; letter-spacing:-.02em !important; line-height:.98 !important;\n  text-shadow:0 4px 30px rgba(0,0,0,.5) !important; }\n.title-sub{ font-style:normal !important; font-weight:500 !important; color:rgba(255,255,255,.9) !important;\n  max-width:24ch; margin-left:auto !important; margin-right:auto !important; }\n\n/* ============================ LIBRARY (premium, light) ============================ */\n#library{ background:\n  radial-gradient(120% 70% at 50% -8%, #fff 0%, rgba(255,255,255,0) 46%),\n  linear-gradient(180deg, var(--jt-canvas) 0%, var(--jt-canvas2) 100%) !important; }\n#library .jts .wm{ color:var(--jt-ink) !important; text-shadow:none !important; }\n.lib-head{ padding:9vh 7vw 2.4vh !important; }\n.lib-head h2{ color:var(--jt-ink) !important; font-weight:900 !important; letter-spacing:-.03em !important; font-size:clamp(28px,8vw,40px) !important; }\n.lib-head p{ color:var(--jt-muted) !important; font-style:normal !important; font-weight:500 !important; }\n\n.lib-grid{ gap:16px !important; padding:1.5vh 5vw 12vh !important; }\n.tale-card{ width:min(92vw,360px) !important; border-radius:26px !important;\n  background:var(--jt-surface) !important; border:1px solid var(--jt-line) !important;\n  box-shadow:var(--jt-shadow) !important; }\n.tale-card:hover{ transform:translateY(-6px) !important; border-color:transparent !important;\n  box-shadow:var(--jt-shadow-lg) !important; }\n.tale-cover{ height:172px !important; border-radius:26px 26px 0 0; }\n.tale-cover::after{ background:linear-gradient(0deg, rgba(27,22,48,.42), transparent 55%) !important; }\n.tale-cover .badge{ top:12px !important; left:12px !important; border-radius:999px 999px 999px 6px !important;\n  background:rgba(255,255,255,.94) !important; color:var(--jt-ink) !important; border:none !important;\n  font-weight:800 !important; letter-spacing:.02em !important; box-shadow:0 6px 16px -8px rgba(0,0,0,.4) !important; }\n.tale-cover .badge.done{ color:var(--jt-green) !important; }\n.tale-body{ padding:16px 18px 18px !important; gap:.55em !important; }\n.tale-body h3{ color:var(--jt-ink) !important; text-transform:none !important; letter-spacing:-.02em !important;\n  font-weight:800 !important; font-size:21px !important; }\n.tale-body .desc{ color:var(--jt-soft) !important; font-size:14px !important; }\n.tale-meta{ color:var(--jt-muted) !important; gap:.35em .8em !important; }\n.tale-meta span{ background:var(--jt-canvas) !important; padding:.35em .7em; border-radius:9px; }\n.tale-meta b{ color:var(--jt-violet-ink) !important; font-weight:800 !important; }\n.tale-prog{ height:7px !important; border-radius:99px !important; background:var(--jt-canvas2) !important; margin-top:.2em; }\n.tale-prog i{ background:linear-gradient(90deg,var(--jt-violet),var(--jt-cyan)) !important; border-radius:99px; }\n.tale-card .btn{ align-self:stretch !important; margin-top:.5em !important; }\n\n/* ============================ CHARACTER SELECT (light) ============================ */\n#select{ background:\n  radial-gradient(120% 70% at 50% -8%, #fff 0%, rgba(255,255,255,0) 44%),\n  linear-gradient(180deg, var(--jt-canvas) 0%, var(--jt-canvas2) 100%) !important; }\n.hall-head h2{ color:var(--jt-ink) !important; text-transform:none !important; letter-spacing:-.02em !important;\n  font-weight:900 !important; font-size:min(6.6vw,27px) !important; }\n.hall-head p{ color:var(--jt-muted) !important; font-style:normal !important; font-weight:500 !important; }\n.hero-card{ border-radius:28px !important; overflow:hidden;\n  background:linear-gradient(180deg,#fff, #F7F4FE) !important; border:1px solid var(--jt-line) !important;\n  box-shadow:var(--jt-shadow) !important; }\n.hero-card:hover{ transform:translateY(-8px) !important; border-color:transparent !important; box-shadow:var(--jt-shadow-lg) !important; }\n.hero-card .glow{ background:radial-gradient(72% 52% at 50% 62%, rgba(135,75,248,.16), transparent 70%) !important; }\n.hero-card .plate{ background:linear-gradient(0deg, rgba(255,255,255,.97) 30%, rgba(255,255,255,.0)) !important; }\n.hero-card .plate h3{ color:var(--jt-ink) !important; text-transform:none !important; letter-spacing:-.02em !important; font-weight:800 !important; }\n.hero-card .plate .role{ color:var(--jt-violet) !important; font-style:normal !important; font-weight:600 !important; }\n.hall-nav{ color:var(--jt-muted) !important; font-style:normal !important; font-weight:600 !important; }\n\n/* ============================ TALE / CHARACTER DETAIL (light) ============================ */\n#detail{ background:\n  radial-gradient(120% 70% at 50% -8%, #fff 0%, rgba(255,255,255,0) 44%),\n  linear-gradient(180deg, var(--jt-canvas) 0%, var(--jt-canvas2) 100%) !important; }\n.detail-glow{ background:radial-gradient(60% 60% at 50% 60%, rgba(135,75,248,.18), transparent 70%) !important; }\n.detail-text{ background:linear-gradient(0deg, var(--jt-canvas2) 12%, rgba(244,241,251,0)) !important; }\n.detail-text h2{ color:var(--jt-ink) !important; text-transform:none !important; letter-spacing:-.03em !important; font-weight:900 !important; }\n.detail-text .role{ color:var(--jt-violet) !important; font-style:normal !important; font-weight:700 !important; }\n.detail-text .power{ color:var(--jt-soft) !important; font-weight:500 !important; }\n\n/* ============================ ENDING (light, premium) ============================ */\n#ending{ background:\n  radial-gradient(120% 80% at 50% -10%, #fff, rgba(255,255,255,0) 50%),\n  linear-gradient(180deg, var(--jt-canvas), var(--jt-canvas2)) !important; }\n#ending .in{ background:var(--jt-surface); border:1px solid var(--jt-line); border-radius:30px;\n  box-shadow:var(--jt-shadow-lg); padding:min(9vw,44px) !important; }\n#ending .in h2{ color:var(--jt-ink) !important; letter-spacing:-.02em; font-weight:900; }\n#ending .in p{ color:var(--jt-soft) !important; }\n\n/* ============================ JOURNAL SHEET (clean, premium) ============================ */\n.parch{ background:var(--jt-surface) !important; border:1px solid var(--jt-line) !important;\n  border-radius:28px !important; box-shadow:var(--jt-shadow-lg) !important; color:var(--jt-ink) !important; }\n.parch-close{ color:var(--jt-muted) !important; }\n.parch-tabs{ border-bottom:1px solid var(--jt-line) !important; }\n.parch-tabs button{ color:var(--jt-muted) !important; font-weight:800 !important; letter-spacing:.02em !important; }\n.parch-tabs button.sel{ color:var(--jt-violet) !important; }\n.parch-tabs button.sel::after{ background:var(--jt-violet) !important; left:24% !important; right:24% !important;\n  height:3px !important; border-radius:99px; }\n.parch-body{ color:var(--jt-soft) !important; }\n.parch-body h4{ color:var(--jt-violet-ink) !important; }\n\n/* ============================ IN-WORLD HUD CHROME (frames the untouched world) ============================ */\n.iconbtn{ border-radius:14px !important; background:rgba(27,18,48,.5) !important;\n  border:1px solid rgba(255,255,255,.14) !important; color:#fff !important; backdrop-filter:blur(10px);\n  box-shadow:0 8px 20px -10px rgba(0,0,0,.5) !important; }\n.portrait{ border-radius:14px !important; box-shadow:0 8px 20px -8px rgba(0,0,0,.55), 0 0 0 2px rgba(255,255,255,.14) !important; }\n#objective{ border-radius:16px !important; background:rgba(27,18,48,.56) !important;\n  border:1px solid rgba(255,255,255,.14) !important; backdrop-filter:blur(12px);\n  box-shadow:0 12px 30px -14px rgba(0,0,0,.55) !important; }\n#chaptercard .cno{ color:var(--jt-cyan) !important; letter-spacing:.28em !important; font-weight:800 !important; }\n#chaptercard .cttl{ letter-spacing:-.02em !important; font-weight:900 !important; }\n#findchip{ border-radius:999px !important; }\n/* --- new controls: per-tale actions + Leave button --- */\n.tale-actions{ display:flex; gap:8px; margin-top:.5em; }\n.tale-actions .btn{ flex:1; margin:0 !important; }\n.leavebtn{ display:inline-flex; align-items:center; gap:.4em; height:42px; padding:0 15px; border-radius:14px;\n  font-family:var(--ui); font-weight:800; font-size:13px; letter-spacing:-.01em; color:#fff; cursor:pointer;\n  background:rgba(27,18,48,.5); border:1px solid rgba(255,255,255,.14); backdrop-filter:blur(10px);\n  box-shadow:0 8px 20px -10px rgba(0,0,0,.5); pointer-events:auto; transition:background .2s, border-color .2s; }\n.leavebtn:hover{ background:rgba(255,99,30,.92); border-color:transparent; }\n.leavebtn .lv-ic{ font-size:16px; line-height:1; }\n"
